import{bQ as a,aL as t,u as r,G as e}from"./chunks/framework.jc7iVf2j.js";const l=JSON.parse('{"title":"简中互联网七诫","description":null,"frontmatter":{"title":"简中互联网七诫","description":null,"date":null,"categories":["社会学人"],"top":false,"copyright":true,"references":null,"cover":null,"tags":["批判性思维","认知偏差","群体心理","伦理","社会观察","必读"],"head":[["link",{"rel":"canonical","href":"https://blog.f0.nz/posts/简中互联网七诫"}]]},"headers":[],"relativePath":"posts/简中互联网七诫.md","filePath":"posts/简中互联网七诫.md","lastUpdated":1780732666000}');const o=a({name:"posts/简中互联网七诫.md"},[["render",function(a,l,o,i,s,n){return t(),r("div",null,[...l[0]||(l[0]=[e('<h2 id="诫一·独立思考-——思考是很累-但不要让别人替你思考" tabindex="-1">诫一·独立思考 ——思考是很累，但不要让别人替你思考 <a class="header-anchor" href="#诫一·独立思考-——思考是很累-但不要让别人替你思考" aria-label="Permalink to &quot;诫一·独立思考 ——思考是很累，但不要让别人替你思考&quot;">​</a></h2><p>陷入他人思考的路径分三个阶段：&quot;被其支配（吸收）&quot;、&quot;自己回味（反思）&quot;、&quot;平和面对（内化）&quot;——大多数人止步于阶段一，把吸收当成了思考本身。<br> 真正的独立思考，要求你在接收信息时始终保持一个基本区分：哪些是可核实的事实陈述，哪些是作者的价值判断和情绪输出。很多时候，两者被刻意混淆在一起，你需要主动把它们拆开。<br> 在此基础上，多信息源交叉验证，突破信息茧房，主动提高逻辑能力，永远保持自省、自我迭代。同时警惕权威崇拜——专家和意见领袖的观点值得参考，但任何结论都应经过你自己的推理检验，而非因为&quot;某某人说了&quot;就全盘接受。<br> 最后，进行慢思考训练：在转发、评论、表态之前，给自己一个冷静期。情绪最激烈的时刻，往往是判断力最差的时刻。</p><h2 id="诫二·叙述中立-——主持人陈述事实时应只描述争议-而不是参与其中-要让事实自己说" tabindex="-1">诫二·叙述中立 ——主持人陈述事实时应只描述争议，而不是参与其中，要让事实自己说 <a class="header-anchor" href="#诫二·叙述中立-——主持人陈述事实时应只描述争议-而不是参与其中-要让事实自己说" aria-label="Permalink to &quot;诫二·叙述中立 ——主持人陈述事实时应只描述争议，而不是参与其中，要让事实自己说&quot;">​</a></h2><p>“完全客观”是不可能的，但可以努力。理论中的完全客观就是“从无处看世界”，仅描述争议，不参与其中，不掺入个人的好恶成见。<br> 主持人可以发表自己的观点，但在陈述事实的环节时，不应在语言上有偏颇（如称“蒋匪”等），要平衡不同观点，给予“同等效力”，为“敌人”写文章。<br> 抵制住贴标签、道德说教、给事件定调的诱惑，读者可能会抗拒你刻意地引导他的思考。让事实自己说话，让读者自己决定。</p><ul><li>写希特勒的文章一开始也没有说“希特勒是个坏蛋”——你根本不需要说他是邪恶的，他自己的行为便可证明他的罪恶罄竹难书。我们只用冷静地列出犹太人大屠杀的事实，并在某种程度上重现死难者痛苦的声音就足以说明这点了。</li></ul><h2 id="诫三·假定善意-——如果愚蠢或误会足以解释一个人的作为-请不要推测其是恶意的" tabindex="-1">诫三·假定善意 ——如果愚蠢或误会足以解释一个人的作为，请不要推测其是恶意的 <a class="header-anchor" href="#诫三·假定善意-——如果愚蠢或误会足以解释一个人的作为-请不要推测其是恶意的" aria-label="Permalink to &quot;诫三·假定善意 ——如果愚蠢或误会足以解释一个人的作为，请不要推测其是恶意的&quot;">​</a></h2><p>请把讨论另一端的用户，视为与你同具有理性见解的人。多数情况，你会发现对方实际上是出于善意，即使是另外的少数情况，负面的沟通态度同样于事无补。<br> 汉隆剃刀是一句哲学剃刀格言：如果可以充分解释为愚蠢，就永远不要归咎于恶意。<br> “假定善意”也有其局限性。心怀善意并不意味着一定可以作出建设性贡献，如果个人能力很糟糕，那么会导致“好心办坏事”的结果。而且对待这类人比对待破坏者更加困难，处理不当的话更容易引发争议。</p><ul><li>维基百科创始人吉米·威尔士：交涉时应当诚实且礼貌。诚实和礼貌都是有客观价值的道德原则。对我说真话，但也不要太过刻薄。不要为了你自己的政治目的而曲解我的观点，我会同样待你的。</li><li>英国前首席新闻秘书伯纳德·英厄姆：许多记者沉醉在政府阴谋论中。我可以担保，如果他们支持的是“政府搞砸论”，报导就会更准确一些。</li></ul><h2 id="诫四·学会让步-——在争论中意识到自己观点的错误时-要主动且明确地让步" tabindex="-1">诫四·学会让步 ——在争论中意识到自己观点的错误时，要主动且明确地让步 <a class="header-anchor" href="#诫四·学会让步-——在争论中意识到自己观点的错误时-要主动且明确地让步" aria-label="Permalink to &quot;诫四·学会让步 ——在争论中意识到自己观点的错误时，要主动且明确地让步&quot;">​</a></h2><p>让步的概念，简单地说，是指以礼相待，明确地让步，而非通过暗示或忽视来避免认输。<br> 作出让步，是向其他人发出信号，表明辩论已经结束，双方可以继续进行建设性的任务。同时，让步有助于消除后续的敌意与对立。</p><ul><li>在政治上，当不同的候选人争夺同一个提名时，输了的候选人发表让步演讲被认为是一个好的做法。（图为麦克·赫卡比在 2008 年总统大选初选时发表让步演讲）</li><li>另一个角度是幸福者退让原则：如果你家庭幸福，生活顺遂，在外遭人挑衅时尽量忍一忍、退一步。因为你永远不知道眼前的这个人，上一秒经历了什么，下一秒能做出什么，你和他发生矛盾的瞬间也许就是压死骆驼的最后一根稻草。<br><a class="img-fancybox" href="https://img.f0.nz/i/2026/05/31/6a1c25a1bc396.png" data-fancybox="gallery" data-caption="迈克发布让步演讲"><img class="post-img" src="https://img.f0.nz/i/2026/05/31/6a1c25a1bc396.png" alt="迈克发布让步演讲" loading="lazy"><span class="post-img-tip">迈克发布让步演讲</span></a></li></ul><h2 id="诫五·警惕民粹——-阶级斗争-不能解决一切-谁穷谁有理-不能解释一切" tabindex="-1">诫五·警惕民粹——“阶级斗争”不能解决一切，“谁穷谁有理”不能解释一切 <a class="header-anchor" href="#诫五·警惕民粹——-阶级斗争-不能解决一切-谁穷谁有理-不能解释一切" aria-label="Permalink to &quot;诫五·警惕民粹——“阶级斗争”不能解决一切，“谁穷谁有理”不能解释一切&quot;">​</a></h2><p>当前简中互联网（2019-至今）存在民粹泛滥成灾的问题。要警惕右，但主要是防止左——无论诉诸群体苦难，还是诉诸国家荣光，只要用集体情绪取代具体论证，就值得警惕。<br> 民粹最惯用的手法，是用情绪替代论证：以身份政治划定阵营，以群体苦难作为压制异见的筹码，以&quot;转移矛盾&quot;代替对具体问题的分析。这套逻辑的核心谬误在于混淆了两件事——一个人的处境值得同情，并不意味着他的判断就是正确的。<br> 不是苦难越深重，观点就越正确。以苦难压制理性讨论，是一种常见的情绪操控手段。识别它，然后拒绝被它裹挟。</p><h2 id="诫六·反二极管-——世界不是非黑即白-中间还有灰色地带" tabindex="-1">诫六·反二极管 ——世界不是非黑即白，中间还有灰色地带 <a class="header-anchor" href="#诫六·反二极管-——世界不是非黑即白-中间还有灰色地带" aria-label="Permalink to &quot;诫六·反二极管 ——世界不是非黑即白，中间还有灰色地带&quot;">​</a></h2><p>&quot;灰度思考&quot;是一种拒绝&quot;非黑即白&quot;的二元对立，学会在复杂模糊的中间地带寻找最佳解决方案的思维方式。二极管思维之所以有害，不仅因为它简化了现实，更因为它经常被用作诡辩工具：把对方推向一个极端，然后用这个极端来为自己的问题开脱。<br> 这就是臭虫论的逻辑——对方做了坏事，所以我做同样的事情不算坏事；当事人有错，所以与其对立的一方就是正确的。两件错事不能互相抵消，对立面的错误也不能被用来淡化、粉饰、洗白自身的问题。<br> 还要警惕假两难谬误：&quot;不支持A就是支持B&quot;——这是最常见的二极管话术，它强迫你在两个选项中二选一，而刻意遮蔽了第三、第四种可能的存在。</p><h2 id="诫七·勇于发声-——不要怯于表达真实想法" tabindex="-1">诫七·勇于发声 ——不要怯于表达真实想法 <a class="header-anchor" href="#诫七·勇于发声-——不要怯于表达真实想法" aria-label="Permalink to &quot;诫七·勇于发声 ——不要怯于表达真实想法&quot;">​</a></h2><p>当人们感知到自己的观点属于少数时，倾向于保持沉默；越多人沉默，主流意见就越显得绝对。即“沉默的螺旋”——你的沉默不是中立，它在客观上加固了这个螺旋。<br> 发声固然是有代价的。但期保持沉默会带来另一种代价：思维的钝化、自我审查成为习惯、公共讨论的质量持续劣化。两种代价都是真实的，在能力范围内，找到你愿意承担的那条线。<br> 你的观点不可能永远和舆论场的主流相符，请试着打逆风团，抵住从众压力，对抗寒蝉效应，打破沉默的螺旋。</p>',17)])])}]]);export{l as __pageData,o as default};
